function solve(code: Array<string>, businessLine: Array<string>, isActive: Array<boolean>): Array<string> {
    const validSet = new Set(["electronics", "grocery", "pharmacy", "restaurant"]);
    const orderMap = {
        "electronics": 0,
        "grocery": 1,
        "pharmacy": 2,
        "restaurant": 3
    };

    let validCoupons: { businessLine: string; code: string; }[] = [];

    const n = code.length;
    for (let i = 0; i < n; i++) {
        if (!isActive[i]) continue;
        if (!validSet.has(businessLine[i])) continue;
        const c = code[i];
        if (c.length === 0) continue;
        if (!/^[A-Za-z0-9_]+$/.test(c)) continue;
        validCoupons.push({ businessLine: businessLine[i], code: c });
    }

    validCoupons.sort((a, b) => {
        const orderA = orderMap[a.businessLine];
        const orderB = orderMap[b.businessLine];
        if (orderA !== orderB) {
            return orderA - orderB;
        }
        return a.code.localeCompare(b.code);
    });

    return validCoupons.map(coupon => coupon.code);
}
```

### Explanation
1. **Initialization**: 
   - `validSet` contains the valid business lines for quick lookup.
   - `orderMap` defines the custom sorting order for business lines.

2. **Validation Check**:
   - For each coupon, check if it is active, has a valid business line, and has a code that is non-empty and consists only of allowed characters (using a regular expression).

3. **Sorting**:
   - Valid coupons are first sorted by their business line using the predefined order in `orderMap`.
   - Within the same business line, coupons are sorted lexicographically by their code.

4. **Result Extraction**:
   - The sorted list of valid coupons is transformed into an array containing only the coupon codes, which is then returned as the result.

This approach efficiently filters and sorts the coupons according to the specified conditions, ensuring the result meets the problem requirements.
